from beeai import Agent
from vex_sdk import VexClient

vex = VexClient(api_key='your-vex-key')
agent = Agent(name='ecommerce-bot')

@vex.listener('agent_state_updated')
def check_memory_growth(event):
    state_size = len(str(event['state']))
    if state_size > 10000:
        vex.alert('Memory exceeded 10KB threshold', event)

agent.add_event_listener(vex)

from beeai.tools import Tool
from vex_sdk import Validator

pricing_tool = Tool(
    name='get_price',
    func=lambda sku: fetch_verified_price(sku)
)

@vex.validator('tool_call')
def validate_pricing(event):
    if event['tool'] == 'get_price':
        sku = event['input']['sku']
        price = pricing_tool.func(sku)
        if abs(price - event['output']) > 0.01:
            raise ValueError('Price mismatch detected')

pricing_tool.add_validator(validate_pricing)
